def validate_identifier(name, allowed_set, identifier_type="identifier"):
    """Validate that an identifier is in the allowlist."""
    if name not in allowed_set:
        raise ValueError(
            f"Invalid {identifier_type}: '{name}'. "
            f"Allowed values: {sorted(allowed_set)}"
        )
    return name


def validate_identifier_format(name):
    """Validate identifier format as additional safety check."""
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', name):
        raise ValueError(
            f"Invalid identifier format: '{name}'. "
            "Only alphanumeric characters and underscores are allowed."
        )
    return name


def require_api_key(f):
    """Simple API key authentication decorator."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        expected_key = os.environ.get('API_KEY', 'dev-api-key')
        if not api_key or api_key != expected_key:
            return jsonify({'error': 'Unauthorized. Provide a valid X-API-Key header.'}), 401
        return f(*args, **kwargs)
    return decorated


def build_select_clause(columns, aggregates=None):
    """
    Build a safe SELECT clause using psycopg2.sql composition.
    
    columns: list of column name strings
    aggregates: list of dicts like {"function": "COUNT", "column": "id", "alias": "total_count"}
    """
    select_parts = []

    if columns:
        for col in columns:
            validate_identifier_format(col)
            validate_identifier(col, ALLOWED_COLUMNS, "column")
            select_parts.append(sql.Identifier(col))

    if aggregates:
        for agg in aggregates:
            func_name = agg.get('function', '').upper()
            col_name = agg.get('column', '*')
            alias = agg.get('alias', f"{func_name.lower()}_{col_name}")

            validate_identifier(func_name, ALLOWED_AGGREGATE_FUNCTIONS, "aggregate function")
            validate_identifier_format(alias)

            if col_name == '*':
                agg_expr = sql.SQL("{}(*)").format(sql.SQL(func_name))
            else:
                validate_identifier_format(col_name)
                validate_identifier(col_name, ALLOWED_COLUMNS, "column")
                agg_expr = sql.SQL("{}({})").format(
                    sql.SQL(func_name),
                    sql.Identifier(col_name)
                )

            select_parts.append(
                sql.SQL("{} AS {}").format(agg_expr, sql.Identifier(alias))
            )

    if not select_parts:
        return sql.SQL("*")

    return sql.SQL(", ").join(select_parts)


def build_where_clause(filters):
    """
    Build a safe WHERE clause using psycopg2.sql composition and parameterized values.
    
    filters: list of dicts like:
        {"column": "status", "operator": "=", "value": "active"}
        {"column": "amount", "operator": "BETWEEN", "value": [100, 500]}
        {"column": "category", "operator": "IN", "value": ["electronics", "books"]}
        {"column": "deleted_at", "operator": "IS NULL"}
        {"logical": "OR"}  # changes the next connector to OR
    
    Returns: (sql_fragment, params_list)
    """
    if not filters:
        return sql.SQL(""), []

    conditions = []
    params = []
    connectors = []
    next_connector = "AND"

    for f in filters:
        # Handle logical connector changes
        if 'logical' in f:
            logical = f['logical'].upper()
            if logical in ('AND', 'OR'):
                next_connector = logical
            continue

        col = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')

        validate_identifier_format(col)
        validate_identifier(col, ALLOWED_COLUMNS, "column")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(
                f"Invalid operator: '{operator}'. "
                f"Allowed operators: {sorted(ALLOWED_OPERATORS)}"
            )

        col_ident = sql.Identifier(col)

        if operator in ('IS NULL', 'IS NOT NULL'):
            condition = sql.SQL("{} {}").format(col_ident, sql.SQL(operator))
        elif operator == 'BETWEEN':
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list of exactly 2 values.")
            condition = sql.SQL("{} BETWEEN {} AND {}").format(
                col_ident, sql.Placeholder(), sql.Placeholder()
            )
            params.extend(value)
        elif operator in ('IN', 'NOT IN'):
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise ValueError(f"{operator} operator requires a non-empty list of values.")
            placeholders = sql.SQL(", ").join([sql.Placeholder()] * len(value))
            condition = sql.SQL("{} {} ({})").format(
                col_ident, sql.SQL(operator), placeholders
            )
            params.extend(value)
        else:
            condition = sql.SQL("{} {} {}").format(
                col_ident, sql.SQL(operator), sql.Placeholder()
            )
            params.append(value)

        if conditions:
            connectors.append(next_connector)
        conditions.append(condition)
        next_connector = "AND"  # Reset to default

    if not conditions:
        return sql.SQL(""), []

    # Build the full WHERE clause with connectors
    where_parts = [conditions[0]]
    for i, cond in enumerate(conditions[1:]):
        connector = connectors[i] if i < len(connectors) else "AND"
        where_parts.append(sql.SQL(f" {connector} "))
        where_parts.append(cond)

    where_clause = sql.SQL(" WHERE ") + sql.SQL("").join(where_parts)
    return where_clause, params


def build_group_by_clause(group_by_columns):
    """Build a safe GROUP BY clause."""
    if not group_by_columns:
        return sql.SQL("")

    identifiers = []
    for col in group_by_columns:
        validate_identifier_format(col)
        validate_identifier(col, ALLOWED_COLUMNS, "column")
        identifiers.append(sql.Identifier(col))

    return sql.SQL(" GROUP BY ") + sql.SQL(", ").join(identifiers)


def build_having_clause(having_conditions):
    """
    Build a safe HAVING clause.
    
    having_conditions: list of dicts like:
        {"function": "COUNT", "column": "id", "operator": ">", "value": 5}
    """
    if not having_conditions:
        return sql.SQL(""), []

    conditions = []
    params = []

    for h in having_conditions:
        func_name = h.get('function', '').upper()
        col_name = h.get('column', '*')
        operator = h.get('operator', '=').upper()
        value = h.get('value')

        validate_identifier(func_name, ALLOWED_AGGREGATE_FUNCTIONS, "aggregate function")
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator in HAVING: '{operator}'")

        if col_name == '*':
            agg_expr = sql.SQL("{}(*)").format(sql.SQL(func_name))
        else:
            validate_identifier_format(col_name)
            validate_identifier(col_name, ALLOWED_COLUMNS, "column")
            agg_expr = sql.SQL("{}({})").format(sql.SQL(func_name), sql.Identifier(col_name))

        condition = sql.SQL("{} {} {}").format(
            agg_expr, sql.SQL(operator), sql.Placeholder()
        )
        conditions.append(condition)
        params.append(value)

    having_clause = sql.SQL(" HAVING ") + sql.SQL(" AND ").join(conditions)
    return having_clause, params


def build_order_by_clause(order_by):
    """
    Build a safe ORDER BY clause.
    
    order_by: list of dicts like {"column": "created_at", "direction": "DESC"}
    """
    if not order_by:
        return sql.SQL("")

    parts = []
    for item in order_by:
        col = item.get('column')
        direction = item.get('direction', 'ASC').upper()

        validate_identifier_format(col)
        validate_identifier(col, ALLOWED_COLUMNS, "column")

        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: '{direction}'")

        parts.append(
            sql.SQL("{} {}").format(sql.Identifier(col), sql.SQL(direction))
        )

    return sql.SQL(" ORDER BY ") + sql.SQL(", ").join(parts)


def build_query(query_spec):
    """
    Build a complete SELECT query from a query specification dict.
    
    Returns: (composed_sql, params)
    """
    # Validate and extract table
    schema = query_spec.get('schema', 'public')
    table = query_spec.get('table')

    if not table:
        raise ValueError("Table name is required.")

    validate_identifier_format(schema)
    validate_identifier(schema, ALLOWED_SCHEMAS, "schema")
    validate_identifier_format(table)
    validate_identifier(table, ALLOWED_TABLES, "table")

    table_ref = sql.SQL("{}.{}").format(sql.Identifier(schema), sql.Identifier(table))

    # Build SELECT
    columns = query_spec.get('columns', [])
    aggregates = query_spec.get('aggregates', [])
    select_clause = build_select_clause(columns, aggregates)

    # Build WHERE
    filters = query_spec.get('filters', [])
    where_clause, where_params = build_where_clause(filters)

    # Build GROUP BY
    group_by = query_spec.get('group_by', [])
    group_by_clause = build_group_by_clause(group_by)

    # Build HAVING
    having = query_spec.get('having', [])
    having_clause, having_params = build_having_clause(having)

    # Build ORDER BY
    order_by = query_spec.get('order_by', [])
    order_by_clause = build_order_by_clause(order_by)

    # Build LIMIT and OFFSET
    limit = min(int(query_spec.get('limit', DEFAULT_LIMIT)), MAX_LIMIT)
    offset = max(int(query_spec.get('offset', 0)), 0)

    limit_offset_clause = sql.SQL(" LIMIT {} OFFSET {}").format(
        sql.Literal(limit), sql.Literal(offset)
    )

    # Compose full query
    query = sql.SQL("SELECT {} FROM {}").format(select_clause, table_ref)
    query += where_clause
    query += group_by_clause
    query += having_clause
    query += order_by_clause
    query += limit_offset_clause

    all_params = where_params + having_params

    return query, all_params


@app.route('/api/v1/query', methods=['POST'])
@require_api_key
def execute_query():
    """
    Execute a dynamic query based on the JSON request body.
    
    Example request body:
    {
        "schema": "public",
        "table": "orders",
        "columns": ["user_id", "status", "amount"],
        "filters": [
            {"column": "status", "operator": "=", "value": "completed"},
            {"column": "amount", "operator": ">=", "value": 100},
            {"column": "created_at", "operator": ">=", "value": "2024-01-01"}
        ],
        "order_by": [{"column": "created_at", "direction": "DESC"}],
        "limit": 50,
        "offset": 0
    }
    """
    try:
        query_spec = request.get_json()
        if not query_spec:
            return jsonify({'error': 'Request body must be valid JSON.'}), 400

        query, params = build_query(query_spec)

        conn = get_db_connection()
        try:
            with conn.cursor(cursor_factory=RealDictCursor) as cur:
                # Log the query for debugging (in production, use proper logging)
                app.logger.info(
                    "Executing query: %s with params: %s",
                    query.as_string(conn),
                    params
                )
                cur.execute(query, params)
                rows = cur.fetchall()
                column_names = [desc[0] for desc in cur.description] if cur.description else []
        finally:
            conn.close()

        return jsonify({
            'success': True,
            'columns': column_names,
            'data': rows,
            'row_count': len(rows),
            'limit': min(int(query_spec.get('limit', DEFAULT_LIMIT)), MAX_LIMIT),
            'offset': max(int(query_spec.get('offset', 0)), 0),
        })

    except ValueError as e:
        return jsonify({'error': f'Validation error: {str(e)}'}), 400
    except psycopg2.Error as e:
        app.logger.error("Database error: %s", str(e))
        return jsonify({'error': 'Database error occurred.'}), 500
    except Exception as e:
        app.logger.error("Unexpected error: %s", str(e))
        return jsonify({'error': 'An unexpected error occurred.'}), 500


