@app.route('/api/v1/table/<table_name>/schema', methods=['GET'])
@require_api_key
def get_table_schema(table_name):
    """Get the schema (column info) for a specific allowed table."""
    try:
        validate_identifier_format(table_name)
        validate_identifier(table_name, ALLOWED_TABLES, "table")

        schema = request.args.get('schema', 'public')
        validate_identifier_format(schema)
        validate_identifier(schema, ALLOWED_SCHEMAS, "schema")

        conn = get_db_connection()
        try:
            with conn.cursor(cursor_factory=RealDictCursor) as cur:
                # Use parameterized query for the information_schema lookup
                cur.execute(
                    """
                    SELECT column_name, data_type, is_nullable, column_default
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    ORDER BY ordinal_position
                    """,
                    (schema, table_name)
                )
                columns = cur.fetchall()
        finally:
            conn.close()

        # Filter to only show allowed columns
        filtered_columns = [
            col for col in columns if col['column_name'] in ALLOWED_COLUMNS
        ]

        return jsonify({
            'success': True,
            'schema': schema,
            'table': table_name,
            'columns': filtered_columns,
        })

    except ValueError as e:
        return jsonify({'error': f'Validation error: {str(e)}'}), 400
    except psycopg2.Error as e:
        app.logger.error("Database error: %s", str(e))
        return jsonify({'error': 'Database error occurred.'}), 500


@app.route('/api/v1/count', methods=['POST'])
@require_api_key
def count_rows():
    """
    Get the count of rows matching the given filters.
    
    Example request body:
    {
        "table": "orders",
        "filters": [
            {"column": "status", "operator": "=", "value": "completed"}
        ]
    }
    """
    try:
        query_spec = request.get_json()
        if not query_spec:
            return jsonify({'error': 'Request body must be valid JSON.'}), 400

        schema = query_spec.get('schema', 'public')
        table = query_spec.get('table')

        if not table:
            raise ValueError("Table name is required.")

        validate_identifier_format(schema)
        validate_identifier(schema, ALLOWED_SCHEMAS, "schema")
        validate_identifier_format(table)
        validate_identifier(table, ALLOWED_TABLES, "table")

        table_ref = sql.SQL("{}.{}").format(sql.Identifier(schema), sql.Identifier(table))

        filters = query_spec.get('filters', [])
        where_clause, where_params = build_where_clause(filters)

        query = sql.SQL("SELECT COUNT(*) AS total_count FROM {}").format(table_ref)
        query += where_clause

        conn = get_db_connection()
        try:
            with conn.cursor(cursor_factory=RealDictCursor) as cur:
                cur.execute(query, where_params)
                result = cur.fetchone()
        finally:
            conn.close()

        return jsonify({
            'success': True,
            'table': table,
            'count': result['total_count'],
        })

    except ValueError as e:
        return jsonify({'error': f'Validation error: {str(e)}'}), 400
    except psycopg2.Error as e:
        app.logger.error("Database error: %s", str(e))
        return jsonify({'error': 'Database error occurred.'}), 500


@app.route('/api/v1/distinct', methods=['POST'])
@require_api_key
def get_distinct_values():
    """
    Get distinct values for a column, optionally filtered.
    
    Example request body:
    {
        "table": "orders",
        "column": "status",
        "filters": [
            {"column": "created_at", "operator": ">=", "value": "2024-01-01"}
        ],
        "limit": 100
    }
    """
    try:
        query_spec = request.get_json()
        if not query_spec:
            return jsonify({'error': 'Request body must be valid JSON.'}), 400

        schema = query_spec.get('schema', 'public')
        table = query_spec.get('table')
        column = query_spec.get('column')

        if not table:
            raise ValueError("Table name is required.")
        if not column:
            raise ValueError("Column name is required.")

        validate_identifier_format(schema)
        validate_identifier(schema, ALLOWED_SCHEMAS, "schema")
        validate_identifier_format(table)
        validate_identifier(table, ALLOWED_TABLES, "table")
        validate_identifier_format(column)
        validate_identifier(column, ALLOWED_COLUMNS, "column")

        table_ref = sql.SQL("{}.{}").format(sql.Identifier(schema), sql.Identifier(table))
        col_ident = sql.Identifier(column)

        filters = query_spec.get('filters', [])
        where_clause, where_params = build_where_clause(filters)

        limit = min(int(query_spec.get('limit', DEFAULT_LIMIT)), MAX_LIMIT)

        query = sql.SQL("SELECT DISTINCT {} FROM {}").format(col_ident, table_ref)
        query += where_clause
        query += sql.SQL(" ORDER BY {} ASC").format(col_ident)
        query += sql.SQL(" LIMIT {}").format(sql.Literal(limit))

        conn = get_db_connection()
        try:
            with conn.cursor() as cur:
                cur.execute(query, where_params)
                rows = cur.fetchall()
        finally:
            conn.close()

        values = [row[0] for row in rows]

        return jsonify({
            'success': True,
            'table': table,
            'column': column,
            'values': values,
            'count': len(values),
        })

    except ValueError as e:
        return jsonify({'error': f'Validation error: {str(e)}'}), 400
    except psycopg2.Error as e:
        app.logger.error("Database error: %s", str(e))
        return jsonify({'error': 'Database error occurred.'}), 500


@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        conn = get_db_connection()
        with conn.cursor() as cur:
            cur.execute("SELECT 1")
        conn.close()
        db_status = "healthy"
    except Exception:
        db_status = "unhealthy"

    return jsonify({
        'status': 'ok',
        'database': db_status,
    })


